17	  customer: Customer;
18	  steps: QuoteStep[];
19	}
20	
21	interface QuoteResult {
22	  premium: number;
23	}
24	
25	const PROCESSING_FEE = 5;
26	const FIRST_INSURANCE_RATE = 0.1;
27	const LOYALTY_RATE = 0.2;
28	const LOYALTY_THRESHOLD_YEARS = 2;
29	const CURSED_RATE = 0.5;
30	const HIGH_ENCHANTMENT_RATE = 0.3;
31	const HIGH_ENCHANTMENT_THRESHOLD = 5;
32	const FOLLOW_UP_RATE = 0.15;
33	const BLOCK_SIZE = 3;
34	const BLOCK_BASE_PREMIUM = 60;
35	
36	const BASE_PREMIUM: Record<string, number> = {
37	  sword: 100,
38	  amulet: 60,
39	  staff: 80,
40	  potion: 40,
41	  rune: 25,
42	  moonstone: 25,
43	};
44	
45	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
46	
47	const isBuildingBlock = (type: string, count: number): boolean =>
48	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
49	
50	const groupBasePremium = (type: string, count: number): number =>
51	  isBuildingBlock(type, count) ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUM[type];
52	
53	const countByType = (items: Item[]): Map<string, number> =>
54	  items.reduce(
55	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
56	    new Map<string, number>(),
57	  );
58	
59	const policyBase = (items: Item[]): number =>
60	  Array.from(countByType(items)).reduce(
61	    (total, [type, count]) => total + groupBasePremium(type, count),
62	    0,
63	  );
64	
65	const SURCHARGE_RATES: ReadonlyArray<(item: Item) => number> = [
66	  (item) => (item.cursed ? CURSED_RATE : 0),
67	  (item) => ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_RATE : 0),
68	];
69	
70	const itemSurcharges = (item: Item): number => {
71	  const itemBase = BASE_PREMIUM[item.type];
72	  const totalRate = SURCHARGE_RATES.reduce((sum, rate) => sum + rate(item), 0);
73	  return itemBase * totalRate;
74	};
75	
76	const policySurcharges = (items: Item[]): number =>
77	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
78	
79	const firstInsuranceSurcharge = (base: number): number => base * FIRST_INSURANCE_RATE;
80	
81	const loyaltyDiscount = (customer: Customer, base: number): number =>
82	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_RATE : 0;
83	
84	const followUpDiscount = (quoteIndex: number, base: number): number =>
85	  quoteIndex > 0 ? base * FOLLOW_UP_RATE : 0;
86	
87	const quoteStep = (customer: Customer, quoteIndex: number, { items }: QuoteStep): QuoteResult => {
88	  const base = policyBase(items);
89	  const additions = policySurcharges(items) + firstInsuranceSurcharge(base) + PROCESSING_FEE;
90	  const deductions = loyaltyDiscount(customer, base) + followUpDiscount(quoteIndex, base);
91	  return { premium: Math.ceil(base + additions - deductions) };
92	};
93	
94	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => ({
95	  results: scenario.steps.map((step, index) => quoteStep(scenario.customer, index, step)),
96	});
